import React, { useState, useEffect } from 'react';
import Logo from './Logo.png'; 
import Menu, { Lunch } from './Menu'; 

const gold = '#D4AF37';
const darkGrey = '#1A1A1A';
const brandPeach = '#FFDAB9'; // Peach from your logo

// --- MOBILE-STYLE WIG STORE ---
const WigStore = () => {
  const categories = [
    {
      type: "Human Hair",
      items: [
        { name: "Luxury Raw Cambodian", price: "85,000", desc: "14-inch frontal unit." }
      ]
    },
    {
      type: "Premium Fibre",
      items: [
        { name: "Sleek Straight Unit", price: "35,000", desc: "Heat resistant & pre-styled." }
      ]
    },
    {
      type: "Hair Blend",
      items: [
        { name: "Piano Wavy T-Closure", price: "25,000", desc: "24-inch high volume blend." }
      ]
    }
  ];

  return (
    <div style={{ padding: '0 15px' }}>
      {categories.map((cat) => (
        <div key={cat.type} style={{ marginBottom: '30px' }}>
          
          {/* CATEGORY LABEL */}
          <h3 style={{ fontSize: '0.8rem', color: gold, textTransform: 'uppercase', letterSpacing: '2px', marginBottom: '15px', borderBottom: '1px solid #111', paddingBottom: '5px' }}>
            {cat.type}
          </h3>

          {/* APP-STYLE LIST ROWS */}
          {cat.items.map((item) => (
            <div key={item.name} style={{ display: 'flex', backgroundColor: '#0A0A0A', borderRadius: '12px', marginBottom: '12px', padding: '12px', alignItems: 'center', border: '1px solid #1a1a1a' }}>
              <div style={{ width: '70px', height: '70px', backgroundColor: '#111', borderRadius: '8px', marginRight: '15px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '0.5rem', color: '#222' }}>IMG</div>
              <div style={{ flex: 1 }}>
                <h4 style={{ fontSize: '0.9rem', margin: '0 0 3px 0', color: '#fff', fontWeight: '500' }}>{item.name}</h4>
                <p style={{ fontSize: '0.7rem', color: '#666', margin: '0 0 5px 0' }}>{item.desc}</p>
                <div style={{ fontSize: '0.95rem', fontWeight: 'bold', color: '#fff' }}>₦{item.price}</div>
              </div>
              <button style={{ backgroundColor: '#fff', color: '#000', border: 'none', borderRadius: '20px', padding: '6px 16px', fontSize: '0.7rem', fontWeight: '700', cursor: 'pointer' }}>ADD</button>
            </div>
          ))}
        </div>
      ))}
    </div>
  );
};

// --- MAIN APP ---
function App() {
  const [activeCategory, setActiveCategory] = useState('Wigs');
  const [currentSlide, setCurrentSlide] = useState(0);

  // Define your product slides here (You will need these files in your /images/ folder)
  const slides = [
    { title: "SMALL CHOPS CURATES", subtitle: "Lagos' best bite, curated.", file: "slide-chops.jpg" },
    { title: "THE HAIR EDIT", subtitle: "Premium Human Hair & Blends.", file: "slide-hair.jpg" },
    { title: "OFFICE LUNCH", subtitle: "Corporate dining, delivered.", file: "slide-food.jpg" }
  ];

  // Auto-slide effect every 4 seconds
  useEffect(() => {
    const timer = setInterval(() => {
      setCurrentSlide((prevSlide) => (prevSlide + 1) % slides.length);
    }, 4000);
    return () => clearInterval(timer);
  }, []);

  return (
    <div style={{ backgroundColor: '#000', minHeight: '100vh', color: '#fff', fontFamily: 'system-ui, sans-serif' }}>
      
      {/* 1. TOP BRAND HEADER (Sticky) */}
      <header style={{ padding: '15px', borderBottom: '1px solid #111', display: 'flex', justifyContent: 'space-between', alignItems: 'center', position: 'sticky', top: 0, backgroundColor: '#000', zIndex: 100 }}>
        <img src={Logo} alt="Logo" style={{ height: '35px' }} />
        <div style={{ display: 'flex', gap: '15px' }}>
          <span>👤</span>
          <span>🛒 <small style={{ background: gold, borderRadius: '50%', padding: '2px 5px', fontSize: '0.6rem', color: '#000' }}>0</small></span>
        </div>
      </header>

      {/* 2. ANIMATED PEACH SLIDESHOW HEADER */}
      <div style={{ 
        width: '100%', 
        height: '220px', 
        position: 'relative', 
        overflow: 'hidden',
        backgroundImage: `linear-gradient(180deg, ${brandPeach}66 0%, #000 100%)` // Peach fade
      }}>
        {slides.map((slide, index) => (
          <div key={slide.title} style={{
            position: 'absolute',
            top: 0,
            left: 0,
            width: '100%',
            height: '100%',
            display: 'flex',
            flexDirection: 'column',
            justifyContent: 'center',
            padding: '0 25px',
            boxSizing: 'border-box',
            
            // Slide Animation Logic
            opacity: index === currentSlide ? 1 : 0,
            transition: 'opacity 1s ease-in-out',
            zIndex: index === currentSlide ? 1 : 0
          }}>
            <h2 style={{ fontSize: '1.6rem', margin: '0 0 8px 0', textShadow: '0 2px 4px rgba(0,0,0,0.8)' }}>
              {slide.title}
            </h2>
            <p style={{ fontSize: '0.8rem', margin: 0, color: '#aaa' }}>
              {slide.subtitle}
            </p>
          </div>
        ))}
      </div>

      {/* 3. BUSINESS INFO BLOCK */}
      <div style={{ padding: '20px' }}>
        <h1 style={{ fontSize: '1.2rem', margin: '0 0 5px 0' }}>Àmí by T - Ikeja Shop</h1>
        <div style={{ fontSize: '0.75rem', color: '#888', display: 'flex', alignItems: 'center', gap: '5px' }}>
          <span style={{ color: '#00FF00' }}>● Opened</span> <span>Closes today at 08:00 PM</span>
        </div>
        
        {/* Pickup/Delivery Buttons */}
        <div style={{ display: 'flex', gap: '10px', marginTop: '20px' }}>
          <button style={{ flex: 1, padding: '12px', borderRadius: '25px', border: 'none', backgroundColor: '#eee', fontWeight: 'bold', fontSize: '0.8rem' }}>Pickup</button>
          <button style={{ flex: 1, padding: '12px', borderRadius: '25px', border: '1px solid #333', backgroundColor: 'transparent', color: '#fff', fontSize: '0.8rem' }}>Delivery</button>
        </div>
      </div>

      {/* 4. SEARCH BAR */}
      <div style={{ padding: '0 20px 20px' }}>
        <div style={{ backgroundColor: '#1A1A1A', borderRadius: '25px', padding: '12px 20px', color: '#666', fontSize: '0.85rem' }}>
          🔍 Search catalog...
        </div>
      </div>

      {/* 5. HORIZONTAL PILL NAVIGATION */}
      <div style={{ display: 'flex', gap: '10px', overflowX: 'auto', padding: '0 20px 20px', scrollbarWidth: 'none' }}>
        {['Wigs', 'Small Chops', 'Office Lunch', 'About'].map((item) => (
          <button 
            key={item} 
            onClick={() => setActiveCategory(item)}
            style={{ 
              whiteSpace: 'nowrap',
              padding: '10px 20px', 
              borderRadius: '20px', 
              border: 'none',
              backgroundColor: activeCategory === item ? '#fff' : '#1A1A1A',
              color: activeCategory === item ? '#000' : '#fff',
              fontSize: '0.8rem',
              fontWeight: '600',
              transition: '0.3s'
            }}
          >
            {item}
          </button>
        ))}
      </div>

      {/* 6. CONTENT AREA */}
      <main style={{ paddingBottom: '100px' }}>
        <h3 style={{ padding: '0 20px 15px', fontSize: '1.1rem', color: '#fff' }}>{activeCategory}</h3>
        {activeCategory === 'Wigs' && <WigStore />}
        {activeCategory === 'Small Chops' && <Menu />}
        {activeCategory === 'Office Lunch' && <Lunch />}
      </main>

    </div>
  );
}

export default App;
